# Minimal customer service agent structure
from anthropic import Anthropic
import json

client = Anthropic()

INTENT_SYSTEM = """
You are a customer service intent classifier. Given a customer message and
conversation history, respond with JSON:
{"intent": "<order_status|return_request|faq|billing|escalate|other>",
 "entities": {"order_id": "...", "account_id": "..."},
 "sentiment": "<positive|neutral|negative|frustrated>"}
"""

def classify_intent(message: str, history: list) -> dict:
    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=256,
        system=INTENT_SYSTEM,
        messages=history + [{"role": "user", "content": message}],
    )
    return json.loads(response.content[0].text)

def route_to_agent(intent: dict, context: dict) -> str:
    if intent["intent"] == "order_status":
        return lookup_order(intent["entities"].get("order_id"), context)
    elif intent["intent"] == "return_request":
        return initiate_return(intent["entities"], context)
    elif intent["intent"] == "faq":
        return kb_search(context["message"])
    elif intent["intent"] == "escalate" or intent["sentiment"] == "frustrated":
        return escalate_to_human(context)
    else:
        return fallback_response(context)

def handle_message(customer_id: str, message: str, session_id: str) -> str:
    history = load_conversation_history(session_id)
    profile = load_customer_profile(customer_id)
    context = {"message": message, "profile": profile, "history": history}
    intent = classify_intent(message, history)
    response = route_to_agent(intent, context)
    response = apply_guardrails(response, intent)
    save_interaction(session_id, message, response, intent)
    return response
